  const [highlightProps, localProps] = splitHighlightBaseProps(props, [
    'query',
    'text',
    'ignoreCase',
    'matchAll',
    'exactMatch',
  ])

  const chunks = useHighlight(highlightProps)

  return (
    <Fragment>
      {chunks.map(({ text, match }, i) =>
