const createStoreHookForAtoms = (): StoreHookForAtoms => {
  const all: object = {}
  const callbacks = new WeakMap<
    AnyAtom | typeof all,
    Set<(atom?: AnyAtom) => void>
  >()
  const notify = (atom: AnyAtom) => {
    callbacks.get(all)?.forEach((fn) => fn(atom))
    callbacks.get(atom)?.forEach((fn) => fn())
  }
  notify.add = (atom: AnyAtom | undefined, fn: (atom?: AnyAtom) => void) => {
    const key = atom || all
    let fns = callbacks.get(key)
    if (!fns) {
      fns = new Set()
      callbacks.set(key, fns)
    }
    fns.add(fn)
    return () => {
      fns!.delete(fn)
      if (!fns!.size) {
        callbacks.delete(key)
      }
    }
  }
  return notify as StoreHookForAtoms
}

const rehydrateSheetFromTag = (sheet: Sheet, style: HTMLStyleElement) => {
  const parts = (style.textContent ?? '').split(SPLITTER);
  const rules: string[] = [];

  for (let i = 0, l = parts.length; i < l; i++) {
    const part = parts[i].trim();
    if (!part) continue;

    const marker = part.match(MARKER_RE);

    if (marker) {
      const group = parseInt(marker[1], 10) | 0;
      const id = marker[2];

      if (group !== 0) {
        setGroupForId(id, group);
        // looks like: data-styled.g11[id="idA"]{content:"nameA,"}
        rehydrateNamesFromContent(sheet, id, marker[3]);
        sheet.getTag().insertRules(group, rules);
      }

      rules.length = 0;
    } else {
      rules.push(part);
    }
  }
};

protected findNextKey(
  fromKey?: Key,
  pred?: (item: Node<T>) => boolean,
  includeDisabled = false
): Key | null {
  let key =
    fromKey != null ? this.collection.getKeyAfter(fromKey) : this.collection.getFirstKey();

  while (key != null) {
    let item = this.collection.getItem(key);
    if (!item) {
      return null;
    }
    if ((includeDisabled || !this.isDisabled(item)) && (!pred || pred(item))) {
      return key;
    }

    key = this.collection.getKeyAfter(key);
    if (key == null) {
      return null;
    }
  }
  return null;
}

function filterNodes<T>(
  collection: Collection<Node<T>>,
  nodes: Iterable<Node<T>>,
  inputValue: string,
  filter: FilterFn
): Iterable<Node<T>> {
  let filteredNode: Node<T>[] = [];
  for (let node of nodes) {
    if (node.type === 'section' && node.hasChildNodes) {
      let filtered = filterNodes(collection, getChildNodes(node, collection), inputValue, filter);
      if ([...filtered].some(node => node.type === 'item')) {
        filteredNode.push({...node, childNodes: filtered});
      }
    } else if (node.type === 'item' && filter(node.textValue, inputValue)) {
      filteredNode.push({...node});
    } else if (node.type !== 'item') {
      filteredNode.push({...node});
    }
  }
  return filteredNode;
}

const getter = <V>(a: Atom<V>) => {
  if (a === (atom as AnyAtom)) {
    const aState = ensureAtomState(buildingBlocks, store, a)
    if (!isAtomStateInitialized(aState)) {
      if (hasInitialValue(a)) {
        setAtomStateValueOrPromise(buildingBlocks, store, a, a.init)
      } else {
        // NOTE invalid derived atoms can reach here
        throw new Error('no atom init')
      }
    }
    return returnAtomValue(aState)
  }
  // a !== atom
  const aState = readAtomState(buildingBlocks, store, a)
  try {
    return returnAtomValue(aState)
  } finally {
    prevDeps.delete(a)
    atomState.d.set(a, aState.n)
    if (isPromiseLike(atomState.v)) {
      addPendingPromiseToDependency(atom, atomState.v, aState)
    }
    if (mountedMap.has(atom)) {
      mountedMap.get(a)?.t.add(atom)
    }
    if (!isSync) {
      mountDependenciesIfAsync()
    }
  }
}

const BUILDING_BLOCK_setAtomStateValueOrPromise: SetAtomStateValueOrPromise = (
  buildingBlocks,
  store,
  atom,
  valueOrPromise,
) => {
  const ensureAtomState = buildingBlocks[11]
  const abortPromise = buildingBlocks[27]
  const atomState = ensureAtomState(buildingBlocks, store, atom)
  const hasPrevValue = 'v' in atomState
  const prevValue = atomState.v
  if (isPromiseLike(valueOrPromise)) {
    for (const a of atomState.d.keys()) {
      addPendingPromiseToDependency(
        atom,
        valueOrPromise,
        ensureAtomState(buildingBlocks, store, a),
      )
    }
  }
  atomState.v = valueOrPromise
  delete atomState.e
  if (!hasPrevValue || !Object.is(prevValue, atomState.v)) {
    ++atomState.n
    if (isPromiseLike(prevValue)) {
      abortPromise(buildingBlocks, store, prevValue)
    }
  }
}

