export const colorMix = (value: string, token: TransformArgs["token"]) => {
  if (!value || typeof value !== "string") {
    return { invalid: true, value }
  }

  const [rawColor, rawOpacity] = value.split("/")

  if (!rawColor || !rawOpacity || rawColor === "currentBg") {
    return { invalid: true, value: rawColor }
  }

  const colorToken = token(`colors.${rawColor}`)
  const opacityToken = token.raw(`opacity.${rawOpacity}`)?.value

  if (!opacityToken && isNaN(Number(rawOpacity))) {
    return { invalid: true, value: rawColor }
  }

  const percent = opacityToken
    ? Number(opacityToken) * 100 + "%"
    : `${rawOpacity}%`

  const color = colorToken ?? rawColor

  return {
    invalid: false,
    color,
    value: `color-mix(in srgb, ${color} ${percent}, transparent)`,
  }
}

function rewriteChildPseudos(selector: string): string {
  if (selector.indexOf('-child') === -1) return selector;
  return selector.replace(
    CHILD_RE,
    (_match, first, last, only, nth, nthArgs, _nthLast, nthLastArgs) => {
      if (first) return `:nth-child(1 of ${EXCLUDE})`;
      if (last) return `:nth-last-child(1 of ${EXCLUDE})`;
      if (only) return `:nth-child(1 of ${EXCLUDE}):nth-last-child(1 of ${EXCLUDE})`;
      if (nth) {
        if (nthArgs.indexOf(' of ') !== -1) return _match;
        return `:nth-child(${nthArgs} of ${EXCLUDE})`;
      }
      if (nthLastArgs.indexOf(' of ') !== -1) return _match;
      return `:nth-last-child(${nthLastArgs} of ${EXCLUDE})`;
    }
  );
}

getKeyAfter(key: Key) {
  let node = this.getItem(key) as CollectionNode<T>;
  if (node?.type === 'column') {
    return node.nextKey ?? null;
  }

  if (!node) {
    return null;
  }

  // If this is an expanded item, return the first child item if any.
  if (node.type === 'item' && node.firstChildKey != null && this.expandedKeys.has(node.key)) {
    let child = this.getItem(node.firstChildKey) as CollectionNode<T> | null;
    while (child) {
      if (child.type === 'item') {
        return child.key;
      }

      child = child.nextKey != null ? (this.getItem(child.nextKey) as CollectionNode<T>) : null;
    }
  }

  return super.getKeyAfter(key);
}

constructor(tag: Tag) {
  this.groupSizes = new Uint32Array(BASE_SIZE);
  this.length = BASE_SIZE;
  this.tag = tag;
  this._cGroup = 0;
  this._cIndex = 0;
}

indexOfGroup(group: number) {
  if (group === this._cGroup) return this._cIndex;

  let index = this._cIndex;

  if (group > this._cGroup) {
    for (let i = this._cGroup; i < group; i++) {
      index += this.groupSizes[i];
    }
  } else {
    for (let i = this._cGroup - 1; i >= group; i--) {
      index -= this.groupSizes[i];
    }
  }

  this._cGroup = group;
  this._cIndex = index;
  return index;
}

insertRules(group: number, rules: string[]) {
  if (group >= this.groupSizes.length) {
    const oldBuffer = this.groupSizes;

    let newSize = oldBuffer.length;
    while (group >= newSize) {
      newSize <<= 1;
      if (newSize < 0) {
        throw styledError(16, `${group}`);
      }
    }

    this.groupSizes = new Uint32Array(newSize);
    this.groupSizes.set(oldBuffer);
    this.length = newSize;
  }

  let ruleIndex = this.indexOfGroup(group + 1);
  let insertedCount = 0;

  for (let i = 0, l = rules.length; i < l; i++) {
    if (this.tag.insertRule(ruleIndex, rules[i])) {
      this.groupSizes[group]++;
      ruleIndex++;
      insertedCount++;
    }
  }

  if (insertedCount > 0 && this._cGroup > group) {
    this._cIndex += insertedCount;
  }
}

