const getLastPart = (functionName: string): string => {
  // The match may be something like 'Object.createEmotionProps' or
  // 'Loader.prototype.render'
  const parts = functionName.split('.')
  return parts[parts.length - 1]
}

const getFunctionNameFromStackTraceLine = (
  line: string
): string | undefined => {
  // V8
  let match = /^\s+at\s+([A-Za-z0-9$.]+)\s/.exec(line)
  if (match) return getLastPart(match[1])

  // Safari / Firefox
  match = /^([A-Za-z0-9$.]+)@/.exec(line)
  if (match) return getLastPart(match[1])

  return undefined
}

function isPlainObject(o: unknown): o is Record<string, any> {
  if (o === null || typeof o !== 'object') return false;
  const proto = Object.getPrototypeOf(o);
  return proto === null || proto === Object.prototype;
}

function deepMergeTheme(outer: DefaultTheme | undefined, inner: DefaultTheme): DefaultTheme {
  if (outer == null) return inner;
  const innerRec = inner as Record<string, unknown>;
  const outerRec = outer as Record<string, unknown>;
  const out: Record<string, unknown> = { ...outerRec };
  for (const k in innerRec) {
    if (!Object.prototype.hasOwnProperty.call(innerRec, k)) continue;
    const v = innerRec[k];
    const o = outerRec[k];
    if (isPlainObject(v) && isPlainObject(o)) {
      out[k] = deepMergeTheme(o, v);
    } else {
      out[k] = v;
    }
  }
  return out;
}

function expandAdjacentSibling(selector: string, out: string[]): void {
  if (selector.indexOf('+') === -1) return;
  let parenDepth = 0;
  let bracketDepth = 0;
  for (let i = 0; i < selector.length; i++) {
    const ch = selector.charCodeAt(i);
    if (ch === $.OPEN_PAREN) parenDepth++;
    else if (ch === $.CLOSE_PAREN) parenDepth--;
    else if (ch === $.OPEN_BRACKET) bracketDepth++;
    else if (ch === $.CLOSE_BRACKET) bracketDepth--;
    else if (ch === $.PLUS && parenDepth === 0 && bracketDepth === 0 && !isEscaped(selector, i)) {
      const before = selector.substring(0, i);
      const after = selector.substring(i + 1);
      out.push(before + '+' + STYLE_TAG + '+' + after);
      out.push(before + '+' + STYLE_TAG + '+' + STYLE_TAG + '+' + after);
    }
  }
}

shouldInvalidateLayoutOptions(newOptions: O, oldOptions: O): boolean {
  return (
    newOptions.maxColumns !== oldOptions.maxColumns ||
    newOptions.dropIndicatorThickness !== oldOptions.dropIndicatorThickness ||
    newOptions.preserveAspectRatio !== oldOptions.preserveAspectRatio ||
    !(newOptions.minItemSize || DEFAULT_OPTIONS.minItemSize).equals(
      oldOptions.minItemSize || DEFAULT_OPTIONS.minItemSize
    ) ||
    !(newOptions.maxItemSize || DEFAULT_OPTIONS.maxItemSize).equals(
      oldOptions.maxItemSize || DEFAULT_OPTIONS.maxItemSize
    ) ||
    !(newOptions.minSpace || DEFAULT_OPTIONS.minSpace).equals(
      oldOptions.minSpace || DEFAULT_OPTIONS.minSpace
    ) ||
    newOptions.maxHorizontalSpace !== oldOptions.maxHorizontalSpace ||
    newOptions.loaderHeight !== oldOptions.loaderHeight ||
    newOptions.direction !== oldOptions.direction
  );
}

